function [cntX,cntY] = fImgCntAnglV01(img,threshold)%% analyze image to get centroid and rotation% for now, output centroid in pixel only% %%% Written by Kei Nakamura% 2016/1/6 ver.1: created% %% internal const%mxAgl = 4;%% get centroidimg = img.*(img>threshold);  % thresholding[sizeY,sizeX] = size(img);  % image sizexPrf = sum(img);    % x profile, integrated in yyPrf = sum(img,2);  % y profile, integrated in x[~,cntX] = fGetRmsV01(1:sizeX,xPrf);  % centroid x[~,cntY] = fGetRmsV01(1:sizeY,yPrf');  % centroid ycntX = round(cntX); cntY = round(cntY);%% symmetrize% if cntX>0.5*sizeX%     rightN = sizeX - cntX;%     leftN = cntX - rightN;%     imgInd = [leftN:sizeX]; % image index%     img2 = img(:,leftN:end);% else%     leftN = cntX - 1;%     rightN = cntX + leftN;%     imgInd = [1:rightN];    % image index%     img2 = img(:,1:rightN);% end% img2 = 0.5*(img2 + fliplr(img2));% % % figure(101)% subplot(2,2,1)% pcolor(log10(img))% shading interp% hold on% plot([1 sizeX],[cntY cntY],'w-')% plot([cntX cntX],[1 sizeY],'w-')% hold off% caxis([0 2])% colorbar% % subplot(2,2,2)% pcolor(log10(img2))% shading interp% hold on% plot([1 sizeX],[cntY cntY],'w-')% plot([cntX cntX],[1 sizeY],'w-')% hold off% caxis([0 2])% colorbar%% rotation scan to see% angle = -1:0.05:1;   % angle to scan% angle = mxAgl*angle;% rotImg = img;   % allocation% xStd = angle;   % allocation% for ii=1:numel(angle)%     rotImg(:,:) = fImageRotV02(img,angle(ii),[cntX,cntY]);%     img2 = rotImg(:,imgInd); % to symmetrize%     img2(:,:) = 0.5*(img2 + fliplr(img2));   % symmetrize%     rotImgX = sum(img2);  % x profile%     [xStd(ii),~] = fGetRmsV01(1:numel(imgInd),rotImgX);  % x-rms% end% % figure(100)% subplot(2,2,1)% plot(xPrf)% subplot(2,2,2)% plot(yPrf)% subplot(2,2,3)% plot(angle,xStd,'r.')
